  MOCK_DOMAINS, 
  MOCK_MAILBOXES, 
  MOCK_METRICS 
} from './constants.tsx';
import { Domain, HealthStatus } from './types';
import { diagnoseDomainHealth } from './geminiService';
import { 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  AreaChart, 
  Area 
} from 'recharts';
import { 
  Bell, 
  Search, 
  FileText, 
  AlertTriangle, 
  Zap, 
  ArrowUpRight, 
  FlaskConical, 
  Thermometer,
  X,
  Activity,
  Stethoscope,
  ChevronDown,
  Trash2,
  MoreHorizontal,
  ClipboardCheck,
  CheckCircle2
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [domains, setDomains] = useState<Domain[]>(MOCK_DOMAINS);
  const [selectedDomainIds, setSelectedDomainIds] = useState<Set<string>>(new Set());

  const [diagnosisDomain, setDiagnosisDomain] = useState<Domain | null>(null);
  const [diagnosisText, setDiagnosisText] = useState<string>('');
  const [isDiagnosing, setIsDiagnosing] = useState(false);
  const [showStatusPicker, setShowStatusPicker] = useState(false);

  const handleDiagnose = async (domain: Domain) => {
    setDiagnosisDomain(domain);
    setIsDiagnosing(true);
    setDiagnosisText('');

    const issues = [];
    if (!domain.spf) issues.push("SPF Record Missing");
    if (!domain.dkim) issues.push("DKIM Authentication Failed");
    if (!domain.dmarc) issues.push("DMARC Policy Weak");
    if (domain.healthScore < 80) issues.push("Low Reputation Score");
    if (!domain.forwarding) issues.push("Catch-all Forwarding Disabled");

    const result = await diagnoseDomainHealth(domain.name, issues);
    setDiagnosisText(result || 'No specific treatment required. Maintain monitoring.');
    setIsDiagnosing(false);
  };

  const toggleSelectAll = () => {
    if (selectedDomainIds.size === domains.length) {
      setSelectedDomainIds(new Set());
    } else {
      setSelectedDomainIds(new Set(domains.map(d => d.id)));
    }
  };

  const toggleSelectDomain = (id: string) => {
    const next = new Set(selectedDomainIds);
    if (next.has(id)) {
      next.delete(id);
    } else {
      next.add(id);
    }
    setSelectedDomainIds(next);
  };

  const handleBulkStatusUpdate = (newStatus: HealthStatus) => {
    setDomains(prev => prev.map(d => 
      selectedDomainIds.has(d.id) ? { ...d, status: newStatus } : d
    ));
    setSelectedDomainIds(new Set());
    setShowStatusPicker(false);
  };

  const handleBulkDiagnose = async () => {
    const selectedDomains = domains.filter(d => selectedDomainIds.has(d.id));
    if (selectedDomains.length === 0) return;

    // We'll show a combined diagnosis for the first one as an example
    // or we could iterate, but for simplicity let's "Triage" the group
    setDiagnosisDomain({
      ...selectedDomains[0],
      name: `Group Triage (${selectedDomains.length} domains)`
    } as Domain);

    setIsDiagnosing(true);
    const combinedIssues = selectedDomains.flatMap(d => {
        const issues = [];
        if (!d.spf) issues.push(`${d.name}: SPF Missing`);
        if (!d.dkim) issues.push(`${d.name}: DKIM Failed`);
        return issues;
    }).slice(0, 5); // Limit for the API call

    const result = await diagnoseDomainHealth("Selected Fleet", combinedIssues);
    setDiagnosisText(result || 'Bulk triage complete. Fleet is stable.');
    setIsDiagnosing(false);
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 ml-64 p-8">
        {/* Header */}
        <header className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-900 tracking-tight">
              {activeTab === 'dashboard' ? 'Infrastructure Triage' : 
               activeTab === 'domains' ? 'The Patient Ward' : 
               activeTab === 'mailboxes' ? 'ICU Monitoring' : 
               'Clinical View'}
            </h2>
            <p className="text-slate-500 text-sm">Welcome back, Chief Surgeon. System health is 94%.</p>
          </div>

          <div className="flex items-center gap-4">
            <div className="relative">
              <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
              <input 
                type="text" 
                placeholder="Search patient records..." 
                className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 transition-all w-64"
              />
            </div>
            <button className="relative p-2 text-slate-400 hover:text-slate-600 transition-colors">
              <Bell className="w-5 h-5" />
              <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-rose-500 rounded-full border-2 border-slate-50"></span>
            </button>
            <div className="h-8 w-[1px] bg-slate-200 mx-2"></div>
            <button className="bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-xl text-sm font-bold shadow-lg shadow-emerald-500/20 flex items-center gap-2 transition-all active:scale-95">
              <Zap className="w-4 h-4 fill-white" />
              New Admission
            </button>
          </div>
        </header>

        {activeTab === 'dashboard' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Vitals Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {[
                { label: 'Total Infrastructure', value: '1,240', sub: 'Domains & Mailboxes', icon: FileText, color: 'indigo' },
                { label: 'Daily Delivery', value: '42.5k', sub: '8.2% vs yesterday', icon: ArrowUpRight, color: 'emerald', trend: 'up' },
                { label: 'Risk Level', value: 'Low', sub: '2 patients critical', icon: AlertTriangle, color: 'amber' },
