                        <div className="flex justify-between items-start mb-2">
                          <p className="text-sm font-semibold">{surgery.name}</p>
                          <span className="text-[10px] text-emerald-400 font-bold uppercase">{surgery.time}</span>
                        </div>
                        <p className="text-xs text-slate-400 mb-3">{surgery.action}</p>
                        <div className="w-full bg-white/10 h-1 rounded-full overflow-hidden">
                          <div className="bg-emerald-500 h-full transition-all duration-1000" style={{ width: `${surgery.progress}%` }}></div>
                        </div>
                      </div>
                    ))}
                  </div>

                  <button className="mt-8 w-full py-4 bg-emerald-500 hover:bg-emerald-400 text-slate-900 font-bold rounded-2xl transition-all active:scale-95 shadow-lg shadow-emerald-500/20">
                    Open Surgery Manager
                  </button>
                </div>
              </div>
            </div>

            {/* Domains List */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {domains.map((domain) => (
                <HealthCard key={domain.id} domain={domain} onDiagnose={handleDiagnose} />
              ))}
            </div>
          </div>
        )}

        {activeTab === 'domains' && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-500">
            {/* Bulk Actions Bar */}
            <div className={`transition-all duration-300 transform ${selectedDomainIds.size > 0 ? 'translate-y-0 opacity-100' : '-translate-y-4 opacity-0 pointer-events-none'}`}>
              <div className="bg-slate-900 rounded-2xl p-4 flex items-center justify-between text-white shadow-xl shadow-slate-900/20 border border-slate-800">
                <div className="flex items-center gap-6">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 bg-emerald-500 rounded-lg flex items-center justify-center">
                      <ClipboardCheck className="w-4 h-4 text-white" />
                    </div>
                    <div>
                      <p className="text-sm font-bold">{selectedDomainIds.size} Patients Selected</p>
                      <p className="text-[10px] text-slate-400 font-semibold uppercase tracking-wider">Group Admission Mode</p>
                    </div>
                  </div>
                  <div className="h-8 w-[1px] bg-slate-800"></div>
                  <div className="flex items-center gap-2">
                    <button 
                      onClick={handleBulkDiagnose}
                      className="px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold flex items-center gap-2 transition-all border border-slate-700"
                    >
                      <FlaskConical className="w-3.5 h-3.5 text-emerald-400" />
                      Bulk Diagnosis
                    </button>
                    <div className="relative">
                        <button 
                            onClick={() => setShowStatusPicker(!showStatusPicker)}
                            className="px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold flex items-center gap-2 transition-all border border-slate-700"
                        >
                            <Activity className="w-3.5 h-3.5 text-blue-400" />
                            Update Status
                            <ChevronDown className="w-3 h-3" />
                        </button>
                        {showStatusPicker && (
                            <div className="absolute top-full left-0 mt-2 w-48 bg-slate-800 border border-slate-700 rounded-xl shadow-2xl z-20 py-1">
                                {Object.values(HealthStatus).map((status) => (
                                    <button
                                        key={status}
                                        onClick={() => handleBulkStatusUpdate(status)}
                                        className="w-full text-left px-4 py-2 text-[11px] font-bold hover:bg-slate-700 text-slate-300 hover:text-white transition-colors flex items-center gap-2"
                                    >
                                        <div className={`w-1.5 h-1.5 rounded-full ${
                                            status === HealthStatus.HEALTHY ? 'bg-emerald-500' :
                                            status === HealthStatus.CRITICAL ? 'bg-rose-500' : 'bg-blue-400'
                                        }`} />
                                        {status}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>
                  </div>
                </div>
                <div className="flex items-center gap-4">
                  <button className="text-slate-400 hover:text-rose-400 transition-colors p-2">
                    <Trash2 className="w-4 h-4" />
                  </button>
                  <button 
                    onClick={() => setSelectedDomainIds(new Set())}
                    className="text-xs font-bold text-slate-400 hover:text-white transition-colors"
                  >
                    Clear Selection
                  </button>
                </div>
              </div>
            </div>

            <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
                <div className="p-8 border-b border-slate-100 flex items-center justify-between">
                <div>
                    <h3 className="text-lg font-bold">Infrastructure Fleet</h3>
                    <p className="text-sm text-slate-500">Managing {domains.length} active domain assets</p>
                </div>
                <div className="flex gap-2">
                    <button className="px-4 py-2 bg-slate-100 text-slate-600 rounded-xl text-sm font-semibold hover:bg-slate-200 transition-colors">Export Records</button>
                    <button className="px-4 py-2 bg-emerald-600 text-white rounded-xl text-sm font-semibold shadow-lg shadow-emerald-500/20 hover:bg-emerald-700 transition-all">Bulk Admission</button>
                </div>
                </div>
                <table className="w-full text-left border-collapse">
                <thead className="bg-slate-50/50 text-slate-500 uppercase text-[10px] font-bold tracking-widest border-b border-slate-100">
                    <tr>
                    <th className="px-8 py-4 w-12">
                        <div 
                        onClick={toggleSelectAll}
                        className={`w-4 h-4 rounded border-2 cursor-pointer flex items-center justify-center transition-all ${
                            selectedDomainIds.size === domains.length 
                            ? 'bg-emerald-500 border-emerald-500' 
                            : 'border-slate-300 hover:border-emerald-400'
                        }`}
                        >
                        {selectedDomainIds.size === domains.length && <CheckCircle2 className="w-3 h-3 text-white" />}
                        </div>
                    </th>
                    <th className="px-4 py-4">Domain Patient</th>
                    <th className="px-8 py-4">Health Status</th>
                    <th className="px-8 py-4">Vitals (DNS)</th>
                    <th className="px-8 py-4">Occupancy</th>
                    <th className="px-8 py-4">Last Exam</th>
                    <th className="px-8 py-4 text-right">Actions</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                    {domains.map((domain) => (
                    <tr 
                        key={domain.id} 
                        className={`hover:bg-slate-50/50 transition-colors group ${selectedDomainIds.has(domain.id) ? 'bg-emerald-50/30' : ''}`}
                    >
                        <td className="px-8 py-5">
                            <div 
                                onClick={() => toggleSelectDomain(domain.id)}
                                className={`w-4 h-4 rounded border-2 cursor-pointer flex items-center justify-center transition-all ${
                                    selectedDomainIds.has(domain.id) 
                                    ? 'bg-emerald-500 border-emerald-500' 
                                    : 'border-slate-300 group-hover:border-emerald-400'
                                }`}
                            >
                                {selectedDomainIds.has(domain.id) && <CheckCircle2 className="w-3 h-3 text-white" />}
                            </div>
                        </td>
                        <td className="px-4 py-5">
                        <p className="font-bold text-slate-900 group-hover:text-emerald-600 transition-colors">{domain.name}</p>
                        <p className="text-xs text-slate-400 font-medium">ID: {domain.id.padStart(5, '0')}</p>
                        </td>
                        <td className="px-8 py-5">
                        <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-bold border transition-all ${
                            domain.status === HealthStatus.HEALTHY ? 'bg-emerald-50 text-emerald-700 border-emerald-200' :
                            domain.status === HealthStatus.CRITICAL ? 'bg-rose-50 text-rose-700 border-rose-200' :
                            'bg-amber-50 text-amber-700 border-amber-200'
                        }`}>
                            <div className={`w-1.5 h-1.5 rounded-full ${
                            domain.status === HealthStatus.HEALTHY ? 'bg-emerald-500 animate-pulse' :
                            domain.status === HealthStatus.CRITICAL ? 'bg-rose-500' :
                            'bg-amber-500'
                            }`}></div>
                            {domain.status}
                        </div>
                        </td>
                        <td className="px-8 py-5">
                        <div className="flex gap-1.5">
                            <span className={`w-8 text-center py-0.5 rounded text-[8px] font-bold transition-colors ${domain.spf ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-400'}`}>SPF</span>
                            <span className={`w-8 text-center py-0.5 rounded text-[8px] font-bold transition-colors ${domain.dkim ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-400'}`}>DKIM</span>
                            <span className={`w-8 text-center py-0.5 rounded text-[8px] font-bold transition-colors ${domain.dmarc ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-400'}`}>DMARC</span>
                        </div>
                        </td>
                        <td className="px-8 py-5">
                        <p className="text-sm font-semibold">{domain.mailboxCount} Mailboxes</p>
                        <div className="w-24 h-1 bg-slate-100 rounded-full mt-1.5">
                            <div className="bg-emerald-500 h-full rounded-full transition-all duration-700" style={{ width: `${(domain.mailboxCount / 10) * 100}%` }}></div>
                        </div>
                        </td>
                        <td className="px-8 py-5 text-sm text-slate-500">{domain.lastChecked}</td>
                        <td className="px-8 py-5 text-right">
                        <div className="flex items-center justify-end gap-2">
                            <button 
                                onClick={() => handleDiagnose(domain)}
                                className="p-2 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-lg transition-all"
                                title="Single Patient Diagnosis"
                            >
                                <FlaskConical className="w-4 h-4" />
                            </button>
                            <button className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-lg transition-all">
                                <MoreHorizontal className="w-4 h-4" />
                            </button>
                        </div>
                        </td>
                    </tr>
                    ))}
                </tbody>
                </table>
            </div>
          </div>
        )}
      </main>

      {/* Diagnosis Modal */}
      {diagnosisDomain && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300" onClick={() => setDiagnosisDomain(null)}></div>
          <div className="bg-white rounded-[32px] w-full max-w-2xl shadow-2xl relative z-10 overflow-hidden animate-in zoom-in-95 slide-in-from-bottom-12 duration-500">
            <div className="bg-slate-900 p-8 text-white flex justify-between items-center">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-500/30">
                  <Activity className="w-6 h-6 text-white" />
                </div>
                <div>
                  <h3 className="text-xl font-bold">Clinical Diagnosis</h3>
                  <p className="text-sm text-slate-400">Analyzing: {diagnosisDomain.name}</p>
                </div>
              </div>
              <button onClick={() => setDiagnosisDomain(null)} className="p-2 hover:bg-white/10 rounded-xl transition-colors">
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="p-8">
              {isDiagnosing ? (
                <div className="flex flex-col items-center justify-center py-20 gap-4">
                  <div className="relative">
                    <div className="w-20 h-20 border-4 border-slate-100 border-t-emerald-500 rounded-full animate-spin"></div>
                    <FlaskConical className="w-8 h-8 text-emerald-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
                  </div>
                  <div className="text-center">
                    <p className="font-bold text-slate-900">Scanning Infrastructure Vitals...</p>
                    <p className="text-sm text-slate-500">The Gemini Surgeon is reviewing DNS records and reputation data.</p>
                  </div>
                </div>
              ) : (
                <div className="space-y-6">
                  <div className="flex items-start gap-4 p-5 bg-emerald-50 border border-emerald-100 rounded-3xl">
                    <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center shrink-0">
                      <Stethoscope className="w-5 h-5 text-white" />
                    </div>
                    <div>
                      <h4 className="font-bold text-emerald-900 mb-1">Surgeon's Findings</h4>
                      <div className="text-sm text-emerald-800 leading-relaxed whitespace-pre-line prose prose-emerald prose-sm max-w-none">
                        {diagnosisText}
                      </div>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="p-4 bg-slate-50 border border-slate-200 rounded-2xl">
                      <p className="text-[10px] font-bold text-slate-400 uppercase mb-2">Patient Health Score</p>
                      <div className="flex items-baseline gap-2">
                        <span className="text-3xl font-bold text-slate-900">{diagnosisDomain.healthScore ?? 85}%</span>
                        <span className={`text-[10px] font-bold ${(diagnosisDomain.healthScore ?? 85) > 80 ? 'text-emerald-500' : 'text-rose-500'}`}>
                          {(diagnosisDomain.healthScore ?? 85) > 80 ? 'CONSIDERED HEALTHY' : 'NEEDS INTERVENTION'}
                        </span>
                      </div>
                    </div>
                    <div className="p-4 bg-slate-50 border border-slate-200 rounded-2xl">
                      <p className="text-[10px] font-bold text-slate-400 uppercase mb-2">Recommended Recovery Time</p>
                      <p className="text-lg font-bold text-slate-900">7-14 Days re-warming</p>
                    </div>
                  </div>

                  <div className="pt-4 flex gap-4">
                    <button 
                        onClick={() => setDiagnosisDomain(null)}
                        className="flex-1 py-4 bg-slate-900 text-white font-bold rounded-2xl hover:bg-slate-800 transition-colors shadow-lg shadow-slate-900/10 active:scale-95"
                    >
                      Execute Surgical Plan
                    </button>
                    <button 
                      onClick={() => setDiagnosisDomain(null)}
                      className="px-8 py-4 border border-slate-200 text-slate-600 font-bold rounded-2xl hover:bg-slate-50 transition-colors active:scale-95"
                    >
                      Close Report
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
